protected void decreaseStatus(ProdParmStatusDecrease _prodParmStatusDecrease)
{
    try
    {
        ttsbegin;
        next decreaseStatus(_prodParmStatusDecrease);

        if(ETGCanadaParameters::find().EnableSubContractingPO)
        {
            ProdTable prodTable = this.initProdTable(_prodParmStatusDecrease.ProdId);

            if(prodTable && prodTable.ETGIsSubContractingOrder && prodTable.ETGParentProdId)
            {
                changecompany(prodTable.ETGParentEntity)
                {
                    ProdParmStatusDecrease prodParmStatusDecrease;
                    ProdTable prodTableParent = ProdTable::find(prodTable.ETGParentProdId);

                    prodParmStatusDecrease.clear();
                    //buf2Buf(_prodParmStatusDecrease,prodParmStatusDecrease);
                    prodParmStatusDecrease.initFromProdTable(prodTableParent);
                    prodParmStatusDecrease.wantedstatus = _prodParmStatusDecrease.WantedStatus;
                    prodParmStatusDecrease.ParmId = NumberSeq::newGetNum(CompanyInfo::numRefParmId()).num();
                    prodParmStatusDecrease.insert();

                    prodMultiStatusDecrease prodMultiStatusDecrease = prodMultiStatusDecrease::construct();
                    prodMultiStatusDecrease.initParmBuffer(prodParmStatusDecrease);
                    prodMultiStatusDecrease.parmId(prodParmStatusDecrease.ParmId);

                    prodMultiStatusDecrease.run();
                }
            }
        }
        ttscommit;
    }
    catch
    {
        ttsabort;
    }

}
